"use client"
import { useState } from 'react'
import { motion } from 'framer-motion'

export default function Reveal({ players, roles, startingPlayer, onComplete }: { players: string[]; roles: Record<string,{role:'imposter'|'civilian'; word:string|null}>; startingPlayer?: string | null; onComplete: () => void }){
  // compute order starting from startingPlayer if provided
  const startIndex = startingPlayer ? players.findIndex(p=>p===startingPlayer) : 0
  const order = startIndex && startIndex > 0 ? [...players.slice(startIndex), ...players.slice(0,startIndex)] : players
  const [index, setIndex] = useState(0)
  const [seen, setSeen] = useState<Record<number,boolean>>({})

  function reveal(){
    setSeen({...seen, [index]: true})
  }

  function next(){
    if (index+1 >= players.length) return onComplete()
    setIndex(i=>i+1)
  }

  const name = order[index]
  const data = roles[name]

  return (
    <motion.div initial={{opacity:0}} animate={{opacity:1}} className="space-y-4">
      <div className="text-sm text-gray-400">Pass the phone to</div>
      <div className="p-6 rounded bg-black/20 text-center">
        <div className="text-lg font-semibold">{name}</div>
        {!seen[index] ? (
          <>
            <div className="mt-4 text-sm text-gray-400">Tap to reveal your role</div>
            <button onClick={reveal} className="mt-4 w-full p-3 bg-neon text-black rounded">Reveal</button>
          </>
        ) : (
            <div className="mt-4 space-y-2">
            <div className="text-sm text-gray-400">Role</div>
            <div className="text-xl neon">{data.role}</div>
            <div className="text-sm text-gray-400 mt-2">Secret</div>
            <div className="p-3 rounded bg-black/10">{data.word ?? '—'}</div>
            <div className="mt-4 text-xs text-gray-400">Hide screen and pass phone</div>
            <button onClick={next} className="mt-2 w-full p-3 bg-white/5 rounded">Done</button>
          </div>
        )}
      </div>
    </motion.div>
  )
}
