"use client"
import { motion } from 'framer-motion'

export default function Results({ roles, onNext }: { roles: Record<string,{role:'imposter'|'civilian'; word:string|null}>; onNext: () => void }){
  const imp = Object.entries(roles).find(([_,v])=>v.role==='imposter')?.[0] ?? 'Unknown'

  return (
    <motion.div initial={{opacity:0}} animate={{opacity:1}} className="space-y-4 text-center">
      <div className="text-sm text-gray-400">In-person play: discuss and vote</div>
      <div className="p-6 rounded bg-black/20">
        <div className="text-sm text-gray-400">Tap to reveal who was the Imposter</div>
        <div className="mt-4">
          <div className="text-lg neon font-semibold">{imp}</div>
        </div>
      </div>
      <div>
        <button onClick={onNext} className="w-full p-3 rounded bg-neon text-black">Next Round</button>
      </div>
    </motion.div>
  )
}
